    example: `import redis
r = redis.Redis()
r.set("inventory", 10)
def buy_item(r):
    with r.pipeline() as pipe:
        while True:
            try:
                pipe.watch("inventory")
                stock = int(pipe.get("inventory"))
                if stock <= 0:
                    raise Exception("Нет в наличии")
                pipe.multi()
                pipe.decr("inventory")
                pipe.execute()
                return True
            except redis.WatchError:
                continue  # кто-то изменил ключ — повторяем
buy_item(r)`,
